const raw = $json.body ?? $json;

const DEFAULT_SQL = "SELECT r.id, r.quality_id, r.name, r.type, r.`desc`, r.src_db, r.src_tbl, r.dest_db, r.dest_tbl, r.src_value, r.dest_value, r.diff, r.`begin`, r.`end`, r.result, r.status, r.src_error, r.dest_error, r.is_repaired, r.created_at, r.updated_at, s.src_sql AS src_sql, s.dest_sql AS dest_sql, s.msg_template AS msg_template FROM wattrel_quality_result r LEFT JOIN wattrel_quality_setting s ON r.quality_id = s.id WHERE r.result = 1 AND r.created_at >= DATE_SUB(NOW(), INTERVAL 3 DAY) ORDER BY r.created_at DESC LIMIT ?";

const COUNTRIES = {
  CN: {
    name: '中国', host: '10.20.47.14', port: 36000,
    envFiles: ['/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/CN-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  TH: {
    name: '泰国', host: '192.168.20.236', port: 36000,
    envFiles: ['/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/TH-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  INE: {
    name: '印尼', host: '192.168.21.236', port: 36000,
    envFiles: ['/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/INE-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  PK: {
    name: '巴基斯坦', host: '10.20.84.176', port: null,
    envFiles: ['/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/PK-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  MX: {
    name: '墨西哥', host: '172.20.220.165', port: 36000,
    envFiles: ['/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/MX-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  PH: {
    name: '菲律宾', host: '10.20.10.12', port: null,
    envFiles: ['/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/PH-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
};

function shellQuote(value) {
  return `'${String(value).replace(/'/g, `'\\''`)}'`;
}

function sqlLiteral(value) {
  if (value === null || value === undefined) return 'NULL';
  if (typeof value === 'number' && Number.isFinite(value)) return String(value);
  return `'${String(value).replace(/\\/g, '\\\\').replace(/'/g, "''")}'`;
}

function interpolateSql(sql, params) {
  let index = 0;
  return String(sql || '').replace(/\?/g, () => sqlLiteral(params[index++]));
}

function normalizeParams(params, limit) {
  if (!Array.isArray(params) || params.length === 0) return [limit];
  return params.map((item) => (item === '${limit}' || item === '{limit}' ? limit : item));
}

const countryCode = String(raw.countryCode || raw.country || '').trim().toUpperCase();
const country = COUNTRIES[countryCode];
const limit = Math.max(1, Math.min(1000, Number(raw.limit || 1000) || 1000));
const params = normalizeParams(raw.params, limit);
const sql = interpolateSql(raw.sql || DEFAULT_SQL, params).replace(/;*\s*$/, '') + ';';
const requestId = String(raw.request_id || raw.requestId || `wattrel-${Date.now()}`);
const errors = [];

if (!country) errors.push(`unsupported country: ${countryCode}`);
if (!sql.trim()) errors.push('sql is required');

if (errors.length) {
  return [{ json: { valid: false, errors, countryCode, countryName: raw.countryName || '', requestId } }];
}

const meta = JSON.stringify({ countryCode, countryName: raw.countryName || country.name, requestId });
const sqlB64 = Buffer.from(sql, 'utf8').toString('base64');
const envFiles = country.envFiles.map(shellQuote).join(' ');
const remoteScript = `set -euo pipefail
for env_file in ${envFiles}; do
  if [ -f "$env_file" ]; then
    set -a
    . "$env_file"
    set +a
    break
  fi
done
: "${'${DB_HOST'}:?DB_HOST missing from wattrel env file}"
: "${'${DB_PORT'}:?DB_PORT missing from wattrel env file}"
: "${'${DB_USER'}:?DB_USER missing from wattrel env file}"
: "${'${DB_PASSWORD'}:?DB_PASSWORD missing from wattrel env file}"
: "${'${DB_NAME'}:?DB_NAME missing from wattrel env file}"
printf %s ${shellQuote(sqlB64)} | base64 -d | MYSQL_PWD="$DB_PASSWORD" mysql --batch --raw --silent --host="$DB_HOST" --port="$DB_PORT" --user="$DB_USER" "$DB_NAME"`;

const sshParts = ['ssh'];
if (country.port) sshParts.push('-p', String(country.port));
sshParts.push('-o', 'BatchMode=yes', '-o', 'ConnectTimeout=20', `root@${country.host}`, `bash -lc ${shellQuote(remoteScript)}`);
const command = `printf '%s\\n' ${shellQuote(`__WATTREL_META__${meta}`)} && ${sshParts.map(shellQuote).join(' ')}`;

return [{
  json: {
    valid: true,
    countryCode,
    countryName: raw.countryName || country.name,
    requestId,
    command,
  },
}];

const raw = $json;
const stdout = String(raw.stdout || '');
const stderr = String(raw.stderr || '').trim();
const exitCode = raw.code ?? raw.exitCode ?? 0;

function parseValue(value) {
  if (value === undefined || value === 'NULL') return null;
  if (/^-?\d+(?:\.\d+)?$/.test(value)) {
    const n = Number(value);
    if (Number.isFinite(n)) return n;
  }
  return value;
}

const lines = stdout.split(/\r?\n/).filter((line) => line.length > 0);
let meta = {};
if (lines[0]?.startsWith('__WATTREL_META__')) {
  try { meta = JSON.parse(lines.shift().replace('__WATTREL_META__', '')); } catch {}
}

if (Number(exitCode) !== 0) {
  return [{ json: { success: false, countryCode: meta.countryCode || '', countryName: meta.countryName || '', requestId: meta.requestId || '', rows: [], rowCount: 0, error: { code: 'COMMAND_FAILED', message: stderr || 'ssh/mysql command failed', exit_code: exitCode } } }];
}

if (!lines.length) {
  return [{ json: { success: true, countryCode: meta.countryCode || '', countryName: meta.countryName || '', requestId: meta.requestId || '', rows: [], rowCount: 0 } }];
}
const headers = lines[0].split('\t');
const rows = lines.slice(1).map((line) => {
  const values = line.split('\t');
  return Object.fromEntries(headers.map((header, index) => [header, parseValue(values[index])]));
});
return [{ json: { success: true, countryCode: meta.countryCode || '', countryName: meta.countryName || '', requestId: meta.requestId || '', rows, rowCount: rows.length } }];
